
%% Notebook 36 MATLAB intermediate mask export
% Generated by notebooks/36_matlab_intermediate_mask_parity.ipynb
% Run in MATLAB with:
%   run('/Users/grosbedou/PycharmProjects/NDORMS/results/notebook36_mask_parity/export_notebook36_masks.m')

clear; clc;

project_root = '/Users/grosbedou/PycharmProjects/NDORMS';
utt_root = '/Users/grosbedou/Documents/GitHub/UltraTimTrack';
out_file = fullfile(project_root, 'results', 'notebook36_mask_parity', 'matlab_intermediate_masks_notebook36.mat');
video_path = fullfile(project_root, 'data', 'raw', 'Test2.mp4');
utt_export_path = fullfile(utt_root, 'UTT_numeric_export.mat');

addpath(genpath(fullfile(utt_root, 'ultrasound-automated-algorithm')));
load(utt_export_path, 'UTT_numeric_export');
parms = UTT_numeric_export.parms;

frames0 = [0 122 533 691 955 1066 1600 2133 2665];  % Python zero-based frames
frames1 = frames0 + 1;  % MATLAB VideoReader one-based frames

v = VideoReader(video_path);
M = struct([]);

fprintf('Exporting Notebook 36 MATLAB masks to:\n%s\n', out_file);

for ii = 1:numel(frames0)
    frame0 = frames0(ii);
    frame1 = frames1(ii);
    fprintf('Frame Python=%d MATLAB=%d\n', frame0, frame1);

    data_rgb = read(v, frame1);
    if ndims(data_rgb) == 3
        data = data_rgb(:,:,1);  % TimTrack uses first RGB channel after squeeze
    else
        data = data_rgb;
    end

    dbg = export_filter_usimage_debug(data, parms);
    [Emask, Emask_radius] = get_fasMask(dbg.fas_thres, dbg.super_vec, dbg.deep_vec, parms.fas);
    fascicle_masked = logical(dbg.fas_thres) & logical(Emask);
    parms_local = parms;
    parms_local.fas.Emask = Emask;
    parms_local.fas.Emask_radius = Emask_radius;

    [alphas, ws, hs, y, x] = dohough(fascicle_masked, parms_local.fas);
    alpha = weightedMedian(alphas, ws);

    M(ii).frame0 = frame0;
    M(ii).frame1 = frame1;
    M(ii).apo_thres = logical(dbg.apo_thres);
    M(ii).apo_super = logical(dbg.apo_super);
    M(ii).apo_deep = logical(dbg.apo_deep);
    M(ii).fas_filt = dbg.fas_filt;
    M(ii).fas_thres_raw = logical(dbg.fas_thres_raw);
    M(ii).fas_thres = logical(dbg.fas_thres);
    M(ii).Emask = logical(Emask);
    M(ii).fascicle_masked = logical(fascicle_masked);
    M(ii).super_vec = dbg.super_vec;
    M(ii).deep_vec = dbg.deep_vec;
    M(ii).super_debug = dbg.super_debug;
    M(ii).deep_debug = dbg.deep_debug;
    M(ii).Emask_radius = Emask_radius;
    M(ii).alphas = alphas;
    M(ii).weights = ws;
    M(ii).h_by_angle = hs;
    M(ii).dohough_y = y;
    M(ii).dohough_x = x;
    M(ii).alpha = alpha;
end

save(out_file, 'M', 'frames0', 'frames1', 'parms', '-v7');
fprintf('Saved %s\n', out_file);

function dbg = export_filter_usimage_debug(data, parms)
    [n, ~] = size(data);

    apo_thres = imbinarize(data, 'adaptive', 'sensitivity', parms.apo.th);

    apo_deep = apo_thres;
    apo_super = apo_thres;

    apo_deep(1:round(parms.apo.deep.cut(1)*n),:) = 0;
    apo_deep((round(parms.apo.deep.cut(2)*n):end),:) = 0;

    apo_super(1:round(parms.apo.super.cut(1)*n),:) = 0;
    apo_super((round(parms.apo.super.cut(2)*n):end),:) = 0;

    [super_vec, super_debug] = get_apo_line_debug(apo_super, parms.apo.apox, 'super');
    [deep_vec, deep_debug] = get_apo_line_debug(apo_deep, parms.apo.apox, 'deep');

    fas_filt = FrangiFilter2D(double(data), parms.fas.frangi);
    fas_thres_raw = imbinarize(fas_filt, 'adaptive', 'sensitivity', parms.fas.th);
    fas_thres = fas_thres_raw;

    % Literal MATLAB Hough-branch behavior from filter_usimage.m:
    % super_vec and deep_vec are y-vectors here, not full image masks.
    fas_thres(super_vec | deep_vec) = 0;

    dbg.apo_thres = apo_thres;
    dbg.apo_super = apo_super;
    dbg.apo_deep = apo_deep;
    dbg.super_vec = super_vec;
    dbg.deep_vec = deep_vec;
    dbg.super_debug = super_debug;
    dbg.deep_debug = deep_debug;
    dbg.fas_filt = fas_filt;
    dbg.fas_thres_raw = fas_thres_raw;
    dbg.fas_thres = fas_thres;
end

function [apoy, debug] = get_apo_line_debug(apo_thres, apox, type)
    [hmat, theta, rho] = hough(apo_thres, 'Theta', [-90:89]);

    rot_angle = 5;
    apo_thres_rot = imrotate(apo_thres, rot_angle, 'nearest', 'crop');
    [hmat_rot, ~, ~] = hough(apo_thres_rot, 'Theta', 90-(rot_angle));
    hmat(:, theta == -90) = hmat_rot;

    P = houghpeaks(hmat, 1, 'Threshold', 0);
    Rho = rho(P(1));
    Theta = theta(P(2));

    yi = round((Rho - apox * cosd(Theta)) ./ sind(Theta));

    if Theta == -90
        yi = -round((Rho - apox * cosd(Theta + rot_angle)) ./ sind(Theta + rot_angle));

        [n, m] = size(apo_thres);
        center = round([m/2, n/2]);
        Cshift = [apox - center(1); yi - center(2)];
        R = [cosd(rot_angle) -sind(rot_angle); sind(rot_angle) cosd(rot_angle)];
        Crot = R * Cshift;
        Ctrans = [Crot(1,:) + center(1); Crot(2,:) + center(2)];
        yi = round(Ctrans(2,:));
    end

    apo_filled = imfill(apo_thres, 'holes');
    apoy = nan(size(apox));

    if strcmp(type, 'super')
        for jj = 1:length(yi)
            if yi(jj) < 1 || yi(jj) + 1 > size(apo_filled, 1)
                continue
            end
            if apo_filled(yi(jj), apox(jj)) || apo_filled(yi(jj)+1, apox(jj))
                idx = find(~apo_filled(yi(jj)+1:end, apox(jj)), 1);
                if ~isempty(idx)
                    apoy(jj) = yi(jj) + idx - 1;
                end
            else
                apoy(jj) = yi(jj);
            end
        end
    elseif strcmp(type, 'deep')
        for jj = 1:length(yi)
            if yi(jj) - 1 < 1 || yi(jj) > size(apo_filled, 1)
                continue
            end
            if apo_filled(yi(jj), apox(jj)) || apo_filled(yi(jj)-1, apox(jj))
                idx = find(~apo_filled(1:yi(jj)-1, apox(jj)), 1, 'last');
                if ~isempty(idx)
                    apoy(jj) = idx + 1;
                end
            else
                apoy(jj) = yi(jj);
            end
        end
    end

    debug.hmat = hmat;
    debug.theta = theta;
    debug.rho = rho;
    debug.P = P;
    debug.Rho = Rho;
    debug.Theta = Theta;
    debug.yi = yi;
end
